#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int N;
    scanf("%d", &N);
    int *wealth = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &wealth[i]);
    }
    for (int i = 0; i < N; i++) {
        int rank = 1;
        int temp[N];
        for (int j = 0; j <= i; j++) {
            temp[j] = wealth[j];
        }
        qsort(temp, i + 1, sizeof(int), compare);
        for (int j = 0; j < i; j++) {
            if (temp[j] > wealth[i]) {
                rank++;
            }
        }
        printf("%d\n", rank);
    }
    free(wealth);
    return 0;
}

