const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function readline() {
    return lines[idx++];
}

let N = parseInt(readline());
let wealth = [];
for (let i = 0; i < N; i++) {
    wealth.push(parseInt(readline()));
}

for (let i = 0; i < N; i++) {
    let rank = 1;
    let temp = wealth.slice(0, i + 1).sort((a, b) => a - b);
    for (let j = 0; j < i; j++) {
        if (temp[j] > wealth[i]) {
            rank++;
        }
    }
    console.log(rank);
}
